// 1) Read date from path/query/body
let inputDate = $('Webhook').first().json.query.date;

// 2) Normalize to string if exists
if (inputDate !== undefined && inputDate !== null) {
    inputDate = String(inputDate).trim();
}

function getFormattedDate(dateStr) {
    if (!dateStr) return null;

    // Handle standard "d/m/yy", "dd/mm/yy", "d.m.yy" etc.
    const parts = dateStr.split(/[./-]/);
    if (parts.length === 3) {
        let [d, m, y] = parts;
        if (y.length === 4) y = y.slice(-2);
        return `${parseInt(d)}/${parseInt(m)}/${y}`;
    }

    // Handle legacy 4-digit format "2326" -> "2/3/26"
    if (/^\d{4}$/.test(dateStr)) {
        const d = dateStr[0];
        const m = dateStr[1];
        const y = dateStr.slice(2);
        return `${d}/${m}/${y}`;
    }

    // Handle 6-digit format "020326" -> "2/3/26"
    if (/^\d{6}$/.test(dateStr)) {
        const d = parseInt(dateStr.slice(0, 2));
        const m = parseInt(dateStr.slice(2, 4));
        const y = dateStr.slice(4);
        return `${d}/${m}/${y}`;
    }

    return null;
}

let parsedDate = getFormattedDate(inputDate);

// 4) If no valid user date → use today's date
if (!parsedDate) {
    const today = new Date();
    const day = today.getDate();
    const month = today.getMonth() + 1;
    const year = String(today.getFullYear()).slice(-2);
    parsedDate = `${day}/${month}/${year}`;
}

// 5) Use parsed date as Excel column key
const dateKey = parsedDate;

// 6) Build result array
const result = items.map(item => ({
  name: item.json["שם"] || "",
  personalNumber: item.json["מספר אישי"] || "",
  department: item.json["מחלקה"] || "",
  role: item.json["תפקיד"] || "",
  todayValue: item.json[dateKey] || "",
  dateUsed: dateKey
}));

// 7) Return array for webhook
return [
  {
    json: {
      data: result
    }
  }
];
